import json, unittest
from pathlib import Path

class TestB(unittest.TestCase):
    def test_totals_match_prices_sum(self):
        root = Path(__file__).resolve().parents[1]
        prices = json.loads(root.joinpath('prices.json').read_text())
        totals = json.loads(root.joinpath('totals.json').read_text())
        self.assertEqual(totals['total_bani'], sum(prices.values()))

if __name__ == '__main__':
    unittest.main()
